var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아닌 줄 알았는데 담이 꽤 크네?","JPN":"そうは見えなかったけど、なかなか度胸あるんだね？","ENG":"I didn't know you could be this daring.","TWN":"沒想到你的膽子不小嘛？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이래 봬도 사귀기 싫은 여자, 동업하기 싫은 용병, 꼴보기 싫은 친구 순위에서 트리플 크라운을 차지한 몸이거든.","JPN":"こう見えてもアタシ、付き合いたくない女、仲間にしたくない傭兵、\\n顔も見たくない友達ランキングで三冠王に輝いてるからね。","ENG":"I'll have you know that I was ranked as the worst date, the most terrible mercenary to work with, and the most hated friend.","TWN":"別看我這樣，在最不想約會的女人、最不想同行的傭兵，最不想見到的朋友排行中，本人可是獲得了三冠王啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아, 참고로 설문은 내가 진행했어.","JPN":"あ、ちなみに、このアンケートはアタシがやったんだ。","ENG":"Ah, to be fair, I was the one who carried out the survey.","TWN":"啊，順帶一提，那個問卷調查是我做的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"후보는 나 한 명♪ 응답자도 나 한 명♬","JPN":"候補はアタシ1人♪回答者もアタシ1人♬","ENG":"And I was the only candidate ♪ and the sole responder. ♬","TWN":"候選人只有我一個♪ 回答者也只有我一個♬"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래서 이런 사람이라도 상관없단 말이지?","JPN":"こんなアタシでもいいってことだよね？","ENG":"So you're saying you don't mind me being so horrible of a person, huh?","TWN":"所以說，就算是這種人你也無所謂嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응응. 이제 와서 상관 있다고 생각해도 늦은 셈 치자고.","JPN":"そうそう。今さら無理って言ってももう遅いから。","ENG":"Well, I guess it's kind of late for you to have second thoughts now.","TWN":"嗯嗯，事到如今，你覺得有所謂也太遲了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이건 사장님한테만 하는 얘기인데, 난 조용하고 얌전한 건 질색이거든.","JPN":"ここだけの話なんだけど、アタシは静かで大人しいのが大嫌いなの。","ENG":"Just between you and me, I don't like to handle things in a quiet, calm fashion.","TWN":"這件事我只告訴老闆一個人喔，其實我最討厭安靜和安分了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러니까 작전 중에 침식체 군집을 끌고 온다거나, 다른 태스크포스에 시비 건다거나 한다고 특별히 싸우고 싶어서 미치겠다는 건 아냐.","JPN":"だから、作戦中に侵食体の群れを連れてきたり、他のタスクフォースカンパニーに喧嘩を売ったりするけど、別に戦いたくてたまらないわけじゃないからね。","ENG":"So when I go wrangle a bunch of C.O.s into a battle or come out swinging at another TASKFORCE team, it's not necessarily because I'm some kind of maniac who's crazy about fighting.","TWN":"所以我才會在作戰中吸引侵蝕體群、去找其他特勤勢力的碴，我真是想戰鬥想瘋了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"익스트림 스포츠는 배우려면 귀찮잖아. 방아쇠만 당겨도 한바탕 난리가 나는데 왜 그런 번거로운 짓을 한담?","JPN":"エクストリームスポーツを学ぶのも面倒じゃん。引き金さえ引けば大騒ぎになるんだから、わざわざ面倒なことをする必要ないし。","ENG":"Learning extreme sports can be a real hassle, but you can enjoy as much excitement by pulling the trigger at a random target. ","TWN":"極限運動學起來不是很麻煩嘛。明明扣下扳機就能不斷引起騷動，為什麼還要做這種麻煩的事情？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"모름지기 뻔한 하루하루를 보내기 싫으면 새로운 자극을 찾아야 하는 법이지.","JPN":"同じ毎日を送りたくなかったら、新しい刺激を探す必要があるよね。","ENG":"If you don't like to spend your day bored, you go looking for thrills yourself.","TWN":"如果你不想過著理所當然的一天又一天，就得找些新的刺激啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"맞다, 따분한 일상에 지쳐 있던 직원들에게 활력을 불어 넣어 줬다고 감사 인사 받아야 하는데!","JPN":"あ、そうだ。退屈な日常に飽きていた社員たちを活気づけたんだから、お礼を言われなくちゃ！","ENG":"Ah, that reminds me. I should tell all the other employees that they should be thanking me for adding fun to their boring lives.","TWN":"沒錯，我可是給那些厭倦無聊日常的員工注入了一股活力，得去接受他們的感謝才行！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다들 내가 어지간히 좋아 죽겠나 봐. 몽둥이 들고 쫓아오던 거 같더라고.","JPN":"みんなもアタシが大好きみたい。確か棍棒を持ってアタシを追ってきてた気がする。","ENG":"They really seem to like me, you know. Before I came here, they were all running at me, with sticks and clubs in their hands.","TWN":"看來大家都愛死我了，還拿著棍子要追我呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러니까 여기 쳐들어오기 전에 얼른 도장 찍으면 안 될까?","JPN":"というわけだから、ここに押しかけてくる前に早くハンコを押してもいい？","ENG":"So can I sign the paper before they come rushing in?","TWN":"所以我們能不能在他們打進來之前快點蓋章啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};